1	// Custom JWT helper for Marketify edge functions.
2	//
3	// Contract: signJwt({ sub, role, session_id }, { ttlSeconds? }) -> compact JWT.
4	//           verifyJwt(token) -> parsed claims or throws.
5	// Algorithm: HS256 (HMAC-SHA256) via Web Crypto.
6	// Secret: MARKETIFY_JWT_SECRET env var — this is OUR signing key, deliberately
7	//         separate from Supabase's built-in JWT secret. Every `/auth/*` edge
8	//         function mints tokens here; RLS policies read `sub` and `role` via
9	//         `auth.jwt()`. `session_id` feeds the denylist lookup in §15c.
10	// Auth:   no inbound auth requirement — this module is a building block.
11	
12	export type UserRole = "creator" | "lister";
13	
14	export interface JwtClaims {
15	  sub: string;
16	  role: UserRole;
17	  session_id: string;
18	  iat: number;
19	  exp: number;
20	}
21	
22	export interface SignInput {
23	  sub: string;
24	  role: UserRole;
25	  session_id: string;
26	}
27	
28	export interface SignOptions {
29	  ttlSeconds?: number;
30	}
31	
32	const DEFAULT_TTL_SECONDS = 7 * 24 * 60 * 60;
33	const encoder = new TextEncoder();
34	const decoder = new TextDecoder();
35	
36	function readSecret(): string {
37	  const s = Deno.env.get("MARKETIFY_JWT_SECRET");
38	  if (!s) throw new Error("MARKETIFY_JWT_SECRET is not set");
39	  return s;
40	}
41	
42	function base64UrlEncode(bytes: Uint8Array): string {
43	  let s = "";
44	  for (const b of bytes) s += String.fromCharCode(b);
45	  return btoa(s).replaceAll("+", "-").replaceAll("/", "_").replace(/=+$/, "");
46	}
47	
48	function base64UrlDecode(input: string): Uint8Array {
49	  const pad = input.length % 4 === 0 ? "" : "=".repeat(4 - (input.length % 4));
50	  const b64 = input.replaceAll("-", "+").replaceAll("_", "/") + pad;
51	  const raw = atob(b64);
52	  const out = new Uint8Array(raw.length);
53	  for (let i = 0; i < raw.length; i++) out[i] = raw.charCodeAt(i);
54	  return out;
55	}
56	
57	async function importKey(secret: string): Promise<CryptoKey> {
58	  return await crypto.subtle.importKey(
59	    "raw",
60	    encoder.encode(secret),
61	    { name: "HMAC", hash: "SHA-256" },
62	    false,
63	    ["sign", "verify"],
64	  );
65	}
66	
67	function constantTimeEqual(a: Uint8Array, b: Uint8Array): boolean {
68	  if (a.length !== b.length) return false;
69	  let diff = 0;
70	  for (let i = 0; i < a.length; i++) diff |= a[i] ^ b[i];
71	  return diff === 0;
72	}
73	
74	export async function signJwt(
75	  input: SignInput,
76	  options: SignOptions = {},
77	): Promise<string> {
78	  const ttl = options.ttlSeconds ?? DEFAULT_TTL_SECONDS;
79	  if (!Number.isFinite(ttl) || ttl <= 0) {
80	    throw new Error("ttlSeconds must be a positive finite number");
81	  }
82	  if (input.role !== "creator" && input.role !== "lister") {
83	    throw new Error("role must be 'creator' or 'lister'");
84	  }
85	
86	  const now = Math.floor(Date.now() / 1000);
87	  const payload: JwtClaims = {
88	    sub: input.sub,
89	    role: input.role,
90	    session_id: input.session_id,
91	    iat: now,
92	    exp: now + ttl,
93	  };
94	
95	  const headerB64 = base64UrlEncode(
96	    encoder.encode(JSON.stringify({ alg: "HS256", typ: "JWT" })),
97	  );
98	  const payloadB64 = base64UrlEncode(encoder.encode(JSON.stringify(payload)));
99	  const signingInput = `${headerB64}.${payloadB64}`;
100	
101	  const key = await importKey(readSecret());
102	  const sig = await crypto.subtle.sign(
103	    "HMAC",
104	    key,
105	    encoder.encode(signingInput),
106	  );
107	  const sigB64 = base64UrlEncode(new Uint8Array(sig));
108	
109	  return `${signingInput}.${sigB64}`;
110	}
111	
112	export async function verifyJwt(token: string): Promise<JwtClaims> {
113	  const parts = token.split(".");
114	  if (parts.length !== 3) throw new Error("Malformed JWT");
115	  const [headerB64, payloadB64, sigB64] = parts;
116	
117	  const header = JSON.parse(decoder.decode(base64UrlDecode(headerB64))) as {
118	    alg?: string;
119	  };
120	  if (header.alg !== "HS256") throw new Error("Unsupported JWT algorithm");
121	
122	  const key = await importKey(readSecret());
123	  const expected = new Uint8Array(
124	    await crypto.subtle.sign(
125	      "HMAC",
126	      key,
127	      encoder.encode(`${headerB64}.${payloadB64}`),
128	    ),
129	  );
130	  const provided = base64UrlDecode(sigB64);
131	  if (!constantTimeEqual(expected, provided)) throw new Error("Bad signature");
132	
133	  const payload = JSON.parse(
134	    decoder.decode(base64UrlDecode(payloadB64)),
135	  ) as Partial<JwtClaims>;
136	
137	  if (
138	    typeof payload.sub !== "string" || payload.sub.length === 0 ||
139	    (payload.role !== "creator" && payload.role !== "lister") ||
140	    typeof payload.session_id !== "string" ||
141	    payload.session_id.length === 0 ||
142	    typeof payload.iat !== "number" ||
143	    typeof payload.exp !== "number"
144	  ) {
145	    throw new Error("JWT missing required claims");
146	  }
147	
148	  const now = Math.floor(Date.now() / 1000);
149	  if (payload.exp <= now) throw new Error("JWT expired");
150	  if (payload.iat > now + 60) throw new Error("JWT iat in the future");
151	
152	  return payload as JwtClaims;
153	}
